/**
 * Adapter: UI and utility re-exports for copy-standalone portability.
 */
"use client";

export { cn } from "@/lib/utils";
export { Button } from "@/components/ui/button";

"use client";

import * as React from "react";

export interface VideoPlaybackState {
  playing: boolean;
  muted: boolean;
}

export interface VideoContextValue {
  state: VideoPlaybackState;
  setState: (patch: Partial<VideoPlaybackState>) => void;
  videoElement: HTMLVideoElement | null;
  setVideoElement: (node: HTMLVideoElement | null) => void;
}

const VideoContext = React.createContext<VideoContextValue | null>(null);

export function useVideo() {
  const ctx = React.useContext(VideoContext);
  if (!ctx) {
    throw new Error("useVideo must be used within a <VideoProvider />");
  }
  return ctx;
}

export interface VideoProviderProps {
  children: React.ReactNode;
  defaultState?: Partial<VideoPlaybackState>;
}

export function VideoProvider({ children, defaultState }: VideoProviderProps) {
  const [state, setStateInternal] = React.useState<VideoPlaybackState>({
    playing: defaultState?.playing ?? false,
    muted: defaultState?.muted ?? true,
  });

  const [videoElement, setVideoElement] =
    React.useState<HTMLVideoElement | null>(null);

  const setState = React.useCallback((patch: Partial<VideoPlaybackState>) => {
    setStateInternal((prev) => ({ ...prev, ...patch }));
  }, []);

  const value = React.useMemo(
    () => ({ state, setState, videoElement, setVideoElement }),
    [state, setState, videoElement],
  );

  return (
    <VideoContext.Provider value={value}>{children}</VideoContext.Provider>
  );
}

"use client";

import {
  ToolUIErrorBoundary,
  type ToolUIErrorBoundaryProps,
} from "@/components/tool-ui/shared";

export function VideoErrorBoundary(
  props: Omit<ToolUIErrorBoundaryProps, "componentName">,
) {
  const { children, ...rest } = props;
  return (
    <ToolUIErrorBoundary componentName="Video" {...rest}>
      {children}
    </ToolUIErrorBoundary>
  );
}

export { Video } from "./video";
export type { VideoProps } from "./video";
export { VideoErrorBoundary } from "./error-boundary";
export { VideoProvider, useVideo } from "./context";
export type { VideoPlaybackState, VideoContextValue } from "./context";
export { SerializableVideoSchema, parseSerializableVideo } from "./schema";
export type { SerializableVideo, Source } from "./schema";

import { z } from "zod";
import {
  ToolUIIdSchema,
  ToolUIReceiptSchema,
  ToolUIRoleSchema,
  parseWithSchema,
} from "@/components/tool-ui/shared";
import { AspectRatioSchema, MediaFitSchema } from "@/components/tool-ui/shared/media";

export const SourceSchema = z.object({
  label: z.string(),
  iconUrl: z.url().optional(),
  url: z.url().optional(),
});

export type Source = z.infer<typeof SourceSchema>;

export const SerializableVideoSchema = z.object({
  id: ToolUIIdSchema,
  role: ToolUIRoleSchema.optional(),
  receipt: ToolUIReceiptSchema.optional(),
  assetId: z.string(),
  src: z.url(),
  poster: z.url().optional(),
  title: z.string().optional(),
  description: z.string().optional(),
  href: z.url().optional(),
  domain: z.string().optional(),
  durationMs: z.number().int().positive().optional(),
  ratio: AspectRatioSchema.optional(),
  fit: MediaFitSchema.optional(),
  createdAt: z.string().datetime().optional(),
  locale: z.string().optional(),
  source: SourceSchema.optional(),
});

export type SerializableVideo = z.infer<typeof SerializableVideoSchema>;

export function parseSerializableVideo(input: unknown): SerializableVideo {
  return parseWithSchema(SerializableVideoSchema, input, "Video");
}

"use client";

import * as React from "react";
import { Play } from "lucide-react";
import { cn, Button } from "./_adapter";
import { ActionButtons, normalizeActionsConfig, type ActionsProp } from "@/components/tool-ui/shared";
import {
  RATIO_CLASS_MAP,
  OVERLAY_GRADIENT,
} from "@/components/tool-ui/shared/media";
import { VideoProvider, useVideo } from "./context";
import type { SerializableVideo } from "./schema";

const FALLBACK_LOCALE = "en-US";

export interface VideoProps extends SerializableVideo {
  className?: string;
  autoPlay?: boolean;
  defaultMuted?: boolean;
  onNavigate?: (href: string, video: SerializableVideo) => void;
  onMediaEvent?: (type: "play" | "pause" | "mute" | "unmute") => void;
  responseActions?: ActionsProp;
  onResponseAction?: (actionId: string) => void | Promise<void>;
  onBeforeResponseAction?: (actionId: string) => boolean | Promise<boolean>;
}

export function Video(props: VideoProps) {
  const {
    defaultMuted = true,
    ...rest
  } = props;

  return (
    <VideoProvider defaultState={{ muted: defaultMuted }}>
      <VideoInner {...rest} />
    </VideoProvider>
  );
}

function VideoInner(props: Omit<VideoProps, "defaultMuted">) {
  const {
    className,
    autoPlay = true,
    onNavigate,
    onMediaEvent,
    responseActions,
    onResponseAction,
    onBeforeResponseAction,
    ...serializable
  } = props;

  const {
    id,
    src,
    poster,
    title,
    ratio = "16:9",
    locale: providedLocale,
  } = serializable;

  const locale = providedLocale ?? FALLBACK_LOCALE;

  const { state, setState, setVideoElement } = useVideo();
  const videoRef = React.useRef<HTMLVideoElement | null>(null);

  React.useEffect(() => {
    setVideoElement(videoRef.current);
    return () => setVideoElement(null);
  }, [setVideoElement]);

  React.useEffect(() => {
    const video = videoRef.current;
    if (!video) return;
    if (video.muted !== state.muted) {
      video.muted = state.muted;
    }
  }, [state.muted]);

  React.useEffect(() => {
    const video = videoRef.current;
    if (!video) return;
    if (state.playing && video.paused) {
      void video.play().catch(() => undefined);
    } else if (!state.playing && !video.paused) {
      video.pause();
    }
  }, [state.playing]);

  const normalizedActions = React.useMemo(
    () => normalizeActionsConfig(responseActions),
    [responseActions],
  );

  const handleWatch = (event: React.MouseEvent<HTMLButtonElement>) => {
    event.preventDefault();
    event.stopPropagation();
    const video = videoRef.current;
    if (!video) return;
    if (video.paused) {
      void video.play().catch(() => undefined);
    } else {
      video.pause();
    }
  };

  return (
    <article
      className={cn("relative w-full min-w-80 max-w-md", className)}
      lang={locale}
      data-tool-ui-id={id}
      data-slot="video"
    >
      <div
        className={cn(
          "group @container relative isolate flex w-full min-w-0 flex-col overflow-hidden rounded-xl",
          "border border-border bg-card text-sm shadow-xs",
        )}
      >
        <div
          className={cn(
            "group relative w-full overflow-hidden bg-black",
            ratio !== "auto" ? RATIO_CLASS_MAP[ratio] : "aspect-video",
          )}
        >
          <video
            ref={videoRef}
            className={cn(
              "relative z-10 h-full w-full object-cover transition-transform duration-200 group-hover:scale-[1.01]",
              ratio !== "auto" && "absolute inset-0 h-full w-full",
            )}
            src={src}
            poster={poster}
            controls
            playsInline
            autoPlay={autoPlay}
            preload="metadata"
            muted={state.muted}
            onPlay={() => {
              setState({ playing: true });
              onMediaEvent?.("play");
            }}
            onPause={() => {
              setState({ playing: false });
              onMediaEvent?.("pause");
            }}
            onVolumeChange={(event) => {
              const target = event.currentTarget;
              setState({ muted: target.muted });
              onMediaEvent?.(target.muted ? "mute" : "unmute");
            }}
          />
          {title && (
            <>
              <div
                className="pointer-events-none absolute inset-x-0 top-0 z-20 h-32 opacity-0 transition-opacity duration-200 group-hover:opacity-100"
                style={{ backgroundImage: OVERLAY_GRADIENT }}
              />
              <div className="absolute inset-x-0 top-0 z-30 flex items-start justify-between px-5 pt-4 opacity-0 transition-opacity duration-200 group-hover:opacity-100">
                <div className="line-clamp-2 max-w-[70%] font-semibold text-white drop-shadow-sm">
                  {title}
                </div>
                <Button
                  variant="default"
                  size="sm"
                  onClick={handleWatch}
                  className="shadow-sm"
                >
                  <Play className="mr-1 h-4 w-4" aria-hidden="true" />
                  Watch
                </Button>
              </div>
            </>
          )}
        </div>
      </div>
      {normalizedActions && (
        <div className="@container/actions mt-3">
          <ActionButtons
            actions={normalizedActions.items}
            align={normalizedActions.align}
            confirmTimeout={normalizedActions.confirmTimeout}
            onAction={(actionId: string) => onResponseAction?.(actionId)}
            onBeforeAction={onBeforeResponseAction}
          />
        </div>
      )}
    </article>
  );
}
